//
import { d3_line, d3_curves } from '../../../core/d3-constants';
import { getMarkValue } from '../../parser/parser-helpers';

function polygonMark(config, cache) {
    let { curve: _curve = 'linear' } = config,
        line = d3_line().curve(d3_curves(_curve));
    return {
        config: {
            d: function(d, i) {
                let node = this,
                    args = [d, i],
                    _points;

                if (config.d) {
                    ({ points: _points } = getMarkValue(node, args, config, 'd', cache));
                } else {
                    _points = getMarkValue(node, args, config, 'points', cache);
                }

                return line(_points);
            }
        },
        depends: {
            d: ['points', 'curve']
        }
    };
}

export { polygonMark };
